import{c as i,Q as l,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/63-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/63-出使德意志皇帝.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/lower/63-出使德意志皇帝.md"};function c(s,a,n,m,d,p){return l(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝",-1),e("p",null,"诸位大人钧鉴： 我的上一封信是在本月16日，由我的信使西莫内从梅明根送去。在那 之后，我进行了一段大约500英里的旅程，有时跟随皇帝，有时跟随枢机 主教。我在9日到达博尔扎诺，而皇帝已经到了。2天后，马基雅维利也来 到这里。他取道萨伏依和瑞士，在伦巴第的时候，他遇到了一个非常严酷 的考验。因为担心②<〈安全问题，他把信件尽数毁去。但是，他口头向我 转述了诸位大人的命令，具体内容如下：诸位大人愿意给国王③一笔高达 50000达克特的金钱，开始先给30000,最后再加到50000。这是为了给 我们的共和国争取到最佳的条款。付款至少分三期进行：第一期，当皇帝 和他的军队到达一个居民都是意大利人的城市时；第二期，当他进入托斯 卡纳境内时；第三期，在3个月后，或更长的时间之后，当他到达罗马， 诸事都能得到最佳安排时。作为回报，诸位大人要求皇帝归还我们的全部 领土，并保全我们现有的政权和领土。但是如果皇帝不能归还全部领土， 那么诸位大人在这一点上可以做出让步。不过，诸位大人想要皇帝能够明 白50000达克特对你们来说不是一笔小数，并且在其他的事情上不会做出 任何让步。另一方面，诸位大人想要以最妥善的方式起草协议，做到字斟 句酌，以此确保诸位大人无须支付超过规定数目的其他钱款，无论是直接 还是间接地交给皇帝，或是交给他的君主或者将军们，或是交给任何和他 有关的其他人。而且，诸位大人不想为了其他的进一步要求而烦恼。无论 提出那些要求的是皇帝本人，还是任何跟随他进入意大利的人，或是后来 进入意大利的什么人。我们共和国的现状必须保持不变，领土必须保持完",-1),e("p",null,"①这些弗朗切斯科 ·韦托里的信件也收在这里，是因为它们大部分出自马基雅维利之手，有助于说明整 个出使任务。——英译本注 ②从此处起用加密文字书写，中译以<〉标注；需要说明的是，英译本与贝尔泰利编校本加密部分略有 出入。——中译者注 ③“罗马人之王”,神圣罗马帝国皇帝由选帝侯选举，选帝侯选举出来的人称“罗马人之王”,由教皇 加冕后称“皇帝”。——英译本注",-1),e("p",null,"Legazioni,commissarie,scritti di governo",-1)])])}const f=i(o,[["render",c]]);export{h as __pageData,f as default};
